+#[derive(Debug)]
+struct SelectiveFailEmbedder {
+    id: &'static str,
+    dim: usize,
+    fill: f32,
+    fail_when_contains: &'static str,
+}
+
+impl SelectiveFailEmbedder {
+    const fn new(
+        id: &'static str,
+        dim: usize,
+        fill: f32,
+        fail_when_contains: &'static str,
+    ) -> Self {
+        Self {
+            id,
+            dim,
+            fill,
+            fail_when_contains,
+        }
+    }
+}
+
+impl Embedder for SelectiveFailEmbedder {
+    fn embed<'a>(&'a self, _cx: &'a Cx, text: &'a str) -> SearchFuture<'a, Vec<f32>> {
+        let dim = self.dim;
+        let fill = self.fill;
+        let id = self.id;
+        let fail_when_contains = self.fail_when_contains;
+        Box::pin(async move {
+            if text.contains(fail_when_contains) {
+                return Err(SearchError::EmbeddingFailed {
+                    model: id.to_owned(),
+                    source: Box::new(io::Error::other("forced embedder failure")),
+                });
+            }
+            Ok(vec![fill; dim])
+        })
+    }
+
+    fn dimension(&self) -> usize {
+        self.dim
+    }
+
+    fn id(&self) -> &str {
+        self.id
+    }
+
+    fn model_name(&self) -> &str {
+        self.id
+    }
+
+    fn is_semantic(&self) -> bool {
+        true
+    }
+
+    fn category(&self) -> ModelCategory {
+        ModelCategory::StaticEmbedder
+    }
+}
